+    #[test]
+    fn test_export_text_respects_markup_setting() {
+        let console = Console::builder().markup(false).build();
+        let output = console.export_text("[bold]Hello[/]");
+        assert_eq!(output, "[bold]Hello[/]\n");
+    }
+
